 37→        $this->service = app(ResignationService::class);
 38→    }
 39→
 40→    /**
 41→     * @apiName 【离职管理】权限负责人列表
 42→     *
 43→     * @return JsonResponse
 44→     */
 45→    public function indexResignationPermissionWhitelist(): JsonResponse
 46→    {
 47→        $permissionInfos = ResignationPermission::where('is_on', 1)->select(['id', 'type', 'ids'])->get()->toArray();
 48→        $ids = collect($permissionInfos)->pluck('ids')->collapse()->unique();
 49→        $userNicknames = SfuserNicknameMapService::app()->ids2Nicknames($ids->toArray());
 50→        $permissionPrincipals = [];
 51→        foreach ($permissionInfos as $permissionInfo) {
 52→            $permissionName = ResignationPermission::USING_PERMISSION_MAP[$permissionInfo['type']];
 53→            $nicknames = [];
 54→            if (!empty($permissionInfo['ids']) && is_array($permissionInfo['ids'])) {
 55→                foreach ($permissionInfo['ids'] as $id) {
 56→                    $nicknames[] = Arr::get($userNicknames, $id, '');
 57→                }
 58→            }
 59→            $permissionPrincipals[] = array_merge($permissionInfo, ['permission_name' => $permissionName], ['nicknames' => $nicknames]);
 60→        }
 61→        // 不在数据库中时
 62→        $types = [];    // 已配置的permission
 63→        if ($permissionInfos) {
 64→            $types = collect($permissionInfos)->pluck('type')->toArray();
 65→        }
 66→        foreach (ResignationPermission::USING_PERMISSION_MAP as $type => $name) {
 67→            if (!in_array($type, $types)) { // 未配置的permission
 68→                $permissionPrincipals[] = [
 69→                    'id' => -1,
 70→                    'type' => $type,
 71→                    'permission_name' => $name,
 72→                    'ids' => [],
 73→                    'nicknames' => [],
 74→                ];
 75→            }
 76→        }
 77→        return $this->responseJsonSuccess(['permissions' => $permissionPrincipals]);
 78→    }
 79→
 80→    /**
 81→     * @apiName 【离职权限】编辑负责人名单
 82→     *
 83→     * @param Request $request
 84→     * @throws \Throwable
 85→     * @return JsonResponse
 86→     */
 87→    public function editResignationPermissionWhitelist(Request $request): JsonResponse
 88→    {
 89→        $input = $request->only(['type', 'ids']);
 90→        $ids = [];
 91→        if (Arr::has($input, 'ids')) {
 92→            $userNicknames = SfuserNicknameMapService::app()->ids2Nicknames($input['ids']);
 93→            $ids = array_keys($userNicknames);
 94→        }
 95→        if (empty($ids)) {
 96→            return $this->responseJsonFail('ids can not be empty');
 97→        }
 98→        if (!in_array($input['type'], array_keys(ResignationPermission::USING_PERMISSION_MAP))) {
 99→            // 暂时只允许使用中的权限更改负责人，但现在还没有废弃的权限，也没有方案。取全部权限也无所谓。但权限是写死的，不能在前端新增。
100→            return $this->responseJsonFail('invalid permission');
101→        }
102→        ResignationCache::clearUserData();
103→        db()->beginTransaction();
104→        try {
105→            ResignationPermission::UpdateOrCreate(
106→                ['type' => $input['type']],
107→                ['ids' => $ids],
108→            );
109→            foreach ($ids as $id) {
110→                Staff::initEmptyRecordIfNotExists($id);
111→            }
112→            db()->commit();
113→        } catch (\Throwable $e) {
114→            db()->rollBack();
115→            Log::error('failed to commit transaction', ['e' => $e->getMessage()]);
116→            return $this->responseJsonFail(__('my_api.db_update_fail'), ServerException::ERR_SERVER_DATABASE);
117→        }
118→        NotifyNumberService::app()->initResignationPermission();
119→        return $this->responseJsonSuccess(['success' => true]);
120→    }
121→
122→    /**
123→     * @apiName 【离职管理】离职员工权限关闭状态列表与搜索
124→     *
125→     * @param Request $request
126→     * @return JsonResponse
127→     */
128→    public function searchResignationSfusers(Request $request)
129→    {
130→        // 花名查询，前端先走sfuser-ids接口，得sfuser_id。
131→        $input = $request->only(['sfuser_id', 'start_date', 'end_date', 'is_accomplished', 'per_page']) + ['per_page' => 20];
132→        $sfuserQuery = ResignationPermissionSfuser::selectRaw('sfuser_id,resignation_date,bit_and(status & 1) as is_accomplished')->groupByRaw('sfuser_id, resignation_date')->orderBy('resignation_date', 'desc');
133→        $sfuserQuery = $this->service->filterByInputAdmin($sfuserQuery, $input);
134→        $resignationSfuser = $sfuserQuery->paginate($input['per_page'])->toArray();
135→        $resignationSfuserData = $resignationSfuser['data'];
136→
137→        $resignationSfuserDetail = ResignationPermissionSfuser::with('operationRecord:id as op_id,resignation_permission_sfusers_id,operation,operator_id,remark,system_remark,postponed_date,created_at,updated_at')
138→            ->get()->groupBy(['sfuser_id', 'resignation_date'])->toArray();
139→        $paginatedData = $this->service->dealWithResignationSfuserData($resignationSfuserDetail, $resignationSfuserData);
140→        return $this->responseJsonSuccess([
141→            'current_page' => $resignationSfuser['current_page'],
142→            'per_page' => $resignationSfuser['per_page'],
143→            'total' => $resignationSfuser['total'],
144→            'resignation_permission_sfusers' => $paginatedData,
145→        ]);
146→    }
147→
148→    /**
149→     * @apiName 【离职管理】录入离职员工
150→     *
151→     * @param Request $request
152→     * @return JsonResponse
153→     */
154→    public function addResignationSfusers(Request $request): JsonResponse
155→    {
156→        // 这段代码写的有点过于复杂了，完全没必要搞这么复杂，先不动这里的逻辑，让前端传递一个额外的参数
157→
158→        $input = $request->only(['sfuser_ids']);
159→        $ebSfusers = $request->input('eb_sfusers', []);
160→        $yaSfusers = $request->input('ya_sfusers', []);
161→        $apitableSfusers = $request->input('apitable_sfusers', []);
162→        $xapitableSfusers = $request->input('xapitable_sfusers', []);
163→        $sfuserIds = Sfuser::whereIn('id', $input['sfuser_ids'])->pluck('id')->toArray();
164→        $date = Carbon::now()->toDateString();
165→        $failedIds = [];
166→        $flag = false;
167→        // 在这里标记花名
168→        $ebNicknames = [];
169→        foreach ($ebSfusers as $ebSfuser) {
170→            $ebNicknames[$ebSfuser['sfuser_id']] = $ebSfuser['nickname'];
171→        }
172→
173→        // 开启大事务
174→        db()->beginTransaction();
175→        try {
176→            $rpsColumns = [];
177→            $sfColumns = [];
178→            foreach ($sfuserIds as $id) {
179→                foreach (ResignationPermission::USING_PERMISSION_MAP as $type => $name) {
180→                    $item = [
181→                        'sfuser_id' => $id,
182→                        'resignation_date' => $date,
183→                        'type' => $type,
184→                        'created_at' => Carbon::now(),
185→                        'updated_at' => Carbon::now(),
186→                        'extra_info' => '{}',
187→                    ];
188→                    // eb 权限关闭，保存下来需要使用的非对称加密的花名
189→                    if ($type == ResignationPermission::EASTBLUE_TYPE) {
190→                        $extraInfo = [
191→                            'eb_nickname' => Arr::get($ebNicknames, $id),
192→                        ];
193→                        $item['extra_info'] = json_encode($extraInfo);
194→                    }
195→                    $rpsColumns[] = $item;
196→                }
197→            }
198→            ResignationPermissionSfuser::insert($rpsColumns);
199→            Sfuser::whereIn('id', $sfuserIds)->update(['status' => 'resignation', 'resignation_date' => $date, 'active' => 0]);
200→            $flag = true;
201→            db()->commit();
202→        } catch (Exception $e) {
203→            db()->rollBack();
204→            $flag = false;
205→            Log::error('failed to commit big transaction', [
206→                'location' => __CLASS__.'@'.__METHOD__.'#'.__LINE__,
207→                'exception_code' => $e->getCode(),
208→                'message' => $e->getMessage(),
209→            ]);
210→        }
211→
212→        // 这代码写得未免太过抽象了。。
213→
214→        // 大事务失败，换小事务一条条尝试。
215→        if (!$flag) {
216→            foreach ($sfuserIds as $sfuserId) {
217→                db()->beginTransaction();
218→                try {
219→                    $rpsColumns = [];
220→                    foreach (ResignationPermission::USING_PERMISSION_MAP as $type => $name) {
221→                        $item = [
222→                            'sfuser_id' => $sfuserId,
223→                            'resignation_date' => $date,
224→                            'type' => $type,
225→                            'created_at' => Carbon::now(),
226→                            'updated_at' => Carbon::now(),
227→                            'extra_info' => '{}',
228→                        ];
229→
230→                        // eb 权限关闭，保存下来需要使用的非对称加密的花名
231→                        if ($type == ResignationPermission::EASTBLUE_TYPE) {
232→                            $extraInfo = [
233→                                'eb_nickname' => Arr::get($ebNicknames, $sfuserId),
234→                            ];
235→                            $item['extra_info'] = json_encode($extraInfo);
236→                        }
237→
238→                        $rpsColumns[] = $item;
239→                    }
240→                    ResignationPermissionSfuser::insert($rpsColumns);
241→                    Sfuser::whereId($sfuserId)->update(['status' => 'resignation', 'resignation_date' => $date, 'active' => 0]);
242→                    db()->commit();
243→                } catch (Exception $e) {
244→                    db()->rollBack();
245→                    $failedIds[] = $sfuserId;
246→                    Log::error('failed to commit transaction', [
247→                        'location' => __CLASS__.'@'.__METHOD__.'#'.__LINE__,
248→                        'exception_code' => $e->getCode(),
249→                        'message' => $e->getMessage(),
250→                    ]);
251→                }
252→            }
253→        }
254→        $successIds = array_diff($sfuserIds, $failedIds);
255→
256→        // 刷新离职缓存
257→        RefreshDailyReportCcUsers::app()->addDismissedSfusers($successIds);
258→        SfuserNotResignedHash2IdMapService::app()->refreshAll(time() - 60);
259→
260→        $num = count($successIds);
261→        if ($num > 0) {
262→            $this->service->sendAdministratorsEmail($successIds);
263→        }
264→
265→        $invalidIds = array_diff($input['sfuser_ids'], $sfuserIds);
266→        $notificationType = ResignationPermissionSfuser::NOTIFICATION_NOW;
267→        if (!app()->environment(['unit_test', 'testing'])) {
268→            register_shutdown_function(function () use ($notificationType, $num, $date) {
269→                dispatch(new SendResignationPermissionNotification($notificationType, $num, $date));
270→            });
271→        } else {
272→            dispatch(new SendResignationPermissionNotification($notificationType, $num, $date));
273→        }
274→        $message = '';  // 错误消息
275→        if ($failedIds) {
276→            // return $this->responseJsonSuccess(['failed_sfuser_ids' => $failedIds, 'msg' => 'duplicate id.']);
277→            $message = $message.'duplicate id:'.implode(',', $failedIds).'.';
278→        }
279→        if ($invalidIds) {  // 可以认为该情况不存在
280→            // return $this->responseJsonSuccess(['failed_sfuser_ids' => $failedIds, 'msg' => 'non-existent id.']);
281→            Log::error('invalid id.', ['location' => __CLASS__.'@'.__METHOD__.'#'.__LINE__, 'ids' => $failedIds]);
282→            $message = $message.'non-existent id:'.implode(',', $failedIds).'.';
283→        }
284→        if ($message) {
285→            return $this->responseJsonFail($message, ExceptionCode::ERR_COMMON_INVALID_ARGUMENTS);
286→        }
287→        $IdToUsingPermissionMap = $this->service->getIdToUsingPermissionMap();
288→        foreach ($IdToUsingPermissionMap as $sfuserId => $permissions) {
289→            NotifyNumberService::app()->modifyIndividual($sfuserId, 'resignation_permission_to_be_executed', $num * count($permissions));
290→        }
291→
292→        // dispatch apitable resignation process
293→        DisableApiTableAccount::dispatch($apitableSfusers, $xapitableSfusers);
294→        NotifyYaUserDismissed::dispatch($yaSfusers);
295→
296→        $dismissedSfuserIds = array_diff($sfuserIds, array_merge($invalidIds, $failedIds));
297→        CloseAppAccess::dispatch($dismissedSfuserIds);
298→        AutoCloseAiChatAccount::dispatch($dismissedSfuserIds);
299→
300→        // 中小服务器负载会比较大，周五下班，因此放到最后
301→        UpdateSfuserCache::dispatch(Sfuser::STRATEGY_REPLACE, [
302→            'updated_after' => time() - 300,
303→        ]);
304→
305→        return $this->responseJsonSuccess(['failed_sfuser_ids' => $failedIds, 'msg' => '']);
306→    }
307→}
