 10→class SfuserNicknameMapService
 11→{
 12→    use TService;
 13→
 14→    public const REDIS_KEY = 'COMMON:SFUSER_ID2NICKNAME_MAP';
 15→
 16→    private mixed $redis;
 17→
 18→    public function __construct()
 19→    {
 20→        $this->redis = redis('shared');
 21→    }
 22→
 23→    /**
 24→     * @throws \RedisException
 25→     * @return false|int|\Redis
 26→     */
 27→    public function clear(): bool|int|Redis
 28→    {
 29→        // 只有中国站点可以清理掉共享缓存
 30→        if (SiteService::app()->is(SiteService::CHN)) {
 31→            return $this->redis->del(static::REDIS_KEY);
 32→        }
 33→
 34→        return false;
 35→    }
 36→
 37→    /**
 38→     * 刷新当前缓存，注意我们没有 clean，clean 的话可能错误地清理了其他地区的数据。
 39→     *
 40→     * @param int $updatedAfter
 41→     * @throws \RedisException
 42→     * @return void
 43→     */
 44→    public function refreshAll(int $updatedAfter = 0): void
 45→    {
 46→        $updatedAfterDateTime = date('Y-m-d H:i:s', $updatedAfter);
 47→        $id2Nickname = Sfuser::where('updated_at', '>=', $updatedAfterDateTime)
 48→            ->where('is_closed', 0)
 49→            ->pluck('nickname', 'id')
 50→            ->toArray();
 51→        // 避免不存在数据时一直创建缓存
 52→        $id2Nickname[0] = '';
 53→
 54→        $this->redis->hMSet(static::REDIS_KEY, $id2Nickname);
 55→    }
 56→
 57→    /**
 58→     * 刷新单个人的花名缓存，注意清理掉旧的花名。
 59→     *
 60→     * @param int $sfuserId
 61→     * @param string $nickname
 62→     * @throws \RedisException
 63→     * @return void
 64→     */
 65→    public function refreshOne(int $sfuserId, string $nickname): void
 66→    {
 67→        $this->redis->hSet(static::REDIS_KEY, $sfuserId, $nickname);
 68→    }
 69→
 70→    /**
 71→     * @param array $ids
 72→     * @throws \App\Exceptions\ServerException
 73→     * @throws \RedisException
 74→     * @return array
 75→     */
 76→    public function ids2Nicknames(array $ids): array
 77→    {
 78→        $ids = array_unique($ids);
 79→        if (!$this->redis->exists(static::REDIS_KEY)) {
 80→            $this->refreshAll();
 81→        }
 82→
 83→        if (empty($ids)) {
 84→            return [];
 85→        }
 86→
 87→        $nicknames = $this->redis->hMGet(static::REDIS_KEY, $ids);
 88→
 89→        foreach ($nicknames as $k => $nickname) {
 90→            // convert false to empty string
 91→            if ($nickname === false) {
 92→                $nicknames[$k] = '';
 93→            }
 94→        }
 95→
 96→        if (count($ids) != count($nicknames)) {
 97→            throw new ServerException('failed to fetch nicknames via sfuser ids');
 98→        }
 99→
100→        return array_combine($ids, $nicknames);
101→    }
102→
103→    public function map(): array
104→    {
105→        return $this->redis->hGetAll(static::REDIS_KEY);
106→    }
107→}
