public function getEbPermissionList(array $input): array
{
    $wr = WorkflowRequest::find($input['request_id']);
    $type = match ($wr->process_key) {
        Registry::EB => WorkflowRequestStakeholder::EB_EXECUTOR_TYPE,
        default => '',
    };
    if (empty($type)) {
        return ['flag' => false, 'msg' => __('my_api.data_not_found')];
    }
    $payload = [
        'applicant_nickname' => $input['applicant_nickname'],
        'approver_nickname' => $input['approver_nickname'],
    ];
    try {
        return EBMasterApiLib::sendRequest('master-api/account-request/get_permission_list', $payload);
    } catch (\Throwable $e) {
        Log::error('查eb权限失败 ', ['e' => $e->getMessage(), 'request_id' => $input['request_id']]);
        throw new ServerException($e->getMessage());
    }
}
