import crypto, {AES, enc, mode as cMode} from 'crypto-js'
import JSEncrypt from 'jsencrypt'

import ebPrivateKey from '@/store/encrypt/ebPrivateKey'
import publicKey from '@/store/encrypt/publicKey'

// AES Key
export function randomKey(): string {
    const array = new Uint8Array(16)
    window.crypto.getRandomValues(array)

    let key = ''
    array.forEach(n => {
        const n16 = n.toString(16)
        key += n16.length === 1 ? '0' + n16 : n16
    })

    return key
}

/**
 * fillKey 后端使用 AES-256-ECB。 crypto-js 默认不支持，需要将密钥手动补0
 * @param key
 */
function fillKey(key: string): string {
    // 补足为 256 位
    let filledKey = new Uint8Array(256 / 8)
    const keys = Uint8Array.from(key.split('').map(el => el.codePointAt(0)))

    if (keys.length < filledKey.length) {
        filledKey = filledKey.map((b, i) => keys[i])
    } else {
        // 长度够 直接返回原key的前32位
        return key.substr(0, 32)
    }
    const resKey = Array.from(filledKey).map(el => String.fromCodePoint(el))
    return resKey.join('')
}

/**
 * AES 对称加密
 * @param key
 * @param message
 */
export function aesEncrypt(key: string, message: string): string {
    return AES.encrypt(message, enc.Utf8.parse(fillKey(key)), {
        mode: cMode.ECB,
    }).toString()
}

/**
 * AES 对称解密
 * @param key
 * @param encrypted
 */
export function aesDecrypt(key: string, encrypted: string): string {
    return AES.decrypt(encrypted, enc.Utf8.parse(fillKey(key)), {
        mode: cMode.ECB,
    }).toString(enc.Utf8)
}

/**
 * 非对称加密密钥
 * @param key
 */
export function keyEncrypt(key: string, pKey = publicKey): string | false {
    const encrypt = new JSEncrypt(undefined)
    encrypt.setPublicKey(pKey)

    return encrypt.encrypt(key)
}

const KEY = crypto.enc.Utf8.parse("+KbPeShVmYq3t6w9");
export function keyEncryptYa(str: string): string {
    const iv = crypto.lib.WordArray.random(16);
    const enc = crypto.AES.encrypt(str, KEY, {
        iv: iv,
        mode: crypto.mode.CBC,
    });
    const result = iv.concat(enc.ciphertext).toString(crypto.enc.Base64);
    return result;
}
export function aesDecryptYa(encStr: string): string {
    const decodeStr = () => {
        const rawData = crypto.enc.Base64.parse(encStr);
        const iv = crypto.lib.WordArray.create(rawData.words.slice(0, 4), 16); // 16 bytes = 4 words
        const ciphertext = crypto.lib.WordArray.create(rawData.words.slice(4), rawData.sigBytes - 16);
        const decrypted = crypto.AES.decrypt({ ciphertext: ciphertext } as any, KEY, {
            iv: iv,
            mode: crypto.mode.CBC,
        });
        return decrypted.toString(crypto.enc.Utf8);
    };

    let text: string = encStr;
    try {
        text = decodeStr();
    } catch {
        console.warn('未解密成功');
        text = encStr;
    }
    return text;
}


export function keyDecrypt(key: string, pKey = ebPrivateKey): string | false {
    const encrypt = new JSEncrypt(undefined)
    encrypt.setPrivateKey(pKey)

    return encrypt.decrypt(key)
}

