/**
 * Read File Async
 * @param file
 */
export function readFileAsync(file: File): Promise<string> {
    return new Promise<string>((resolve, reject) => {
        const reader = new FileReader()

        reader.onload = () => {
            resolve(reader.result as string)
        }

        reader.onerror = reject

        reader.readAsDataURL(file)
    })
}

/**
 * 对应后端的 php: rawurlencode
 * @param string
 */
function fixedEncodeURIComponent(str: string): string {
    return encodeURIComponent(str).replace(/[!'()*]/g, function (c) {
        return '%' + c.charCodeAt(0).toString(16).toUpperCase()
    })
}

/**
 * AES 加密 file
 * @param key
 * @param blob
 */
export async function aesFileEncrypt(key: string, file: File): Promise<File> {
    const val = await readFileAsync(file)
    // 中文文件名处理麻烦，先encodeURLComponent
    const encodeKey = fixedEncodeURIComponent(key)
    const encrypted = aesEncrypt(encodeKey, val)
    const newFile = new File([encrypted], file.name)
    return newFile
}

