// 离职管理相关接口
import dayjs from 'dayjs'
import { cloneDeep, difference, uniq } from 'lodash'

import {
    getSfUserSfUserOwnerIds,
    getStaffAccountAPI,
    sendChangeKnock,
    updateResAttrAPI,
} from '@/apis/StaffManagement'
import axios2 from '@/apis/axios2'
import { getUserByNickName, getUserBySfUserId } from '@/apis/common'
import { ajaxUrl } from '@/appConstant'
import i18n from '@/i18n'
import {keyEncrypt, keyEncryptYa} from '@/store/encrypt'
import aiPublicKey from '@/store/encrypt/aiPublicKey'
import ebPublicKey from '@/store/encrypt/ebPublicKey'
import apitablePublicKey from '@/store/encrypt/apitablePublicKey'
import xapiTablePublicKey from '@/store/encrypt/xapitablePublicKey'

// 当前状态
export type AuthorizationT = Option<string>
export type StatusT = Option<number>
export type AccomplishedT = Option<number>
export type RecordStatusT = Option<number> & {
    // 员工端-权限关闭-离职记录-操作记录中的文案展示也使用了这个字典
    operateAlia?: string
}

// 权限Map
export const AuthorizationMap = new (class {
    private authorizationMap = new Map<AuthorizationT['value'], AuthorizationT>()
    private statusMap = new Map<StatusT['value'], StatusT>()
    private accomplishedMap = new Map<AccomplishedT['value'], AccomplishedT>()
    private recordStatusMap = new Map<RecordStatusT['value'], RecordStatusT>()

    constructor() {
        this.initMap()
    }

    initMap() {
        this.authorizationMap = new Map([
            ['email', { label:<string>i18n.t('resignmanagement_index_521'), value: 'email' }],
            ['knock_and_oc', { label:<string>i18n.t('resignmanagement_index_522'), value: 'knock_and_oc' }],
            ['eb', { label:<string>i18n.t('resignmanagement_index_523'), value: 'eb' }],
            ['administration', { label:<string>i18n.t('resignmanagement_index_524'), value: 'administration' }],
            ['gcp', { label:<string>i18n.t('resignmanagement_index_525'), value: 'gcp' }],
            ['computer_account', { label:<string>i18n.t('resignmanagement_index_526'), value: 'computer_account' }],
            ['computer_format', { label:<string>i18n.t('resignmanagement_index_527'), value: 'computer_format' }],
            ['p4v_account', { label:<string>i18n.t('resignmanagement_index_528'), value: 'p4v_account' }],
            ['jira_account', { label:<string>i18n.t('resignmanagement_index_529'), value: 'jira_account' }],
            ['only_office', { label:<string>i18n.t('constant_index_334'), value: 'only_office' }],
            ['jira_access', { label:<string>i18n.t('constant_index_333'), value: 'jira_access' }],
            ['onlyoffice_access', { label:<string>i18n.t('constant_index_334'), value: 'onlyoffice_access' }],
            ['gcp_access', { label:<string>i18n.t('constant_index_332'), value: 'gcp_access' }],
            ['ai_access', { label:<string>i18n.t('constant_index_331'), value: 'ai_access' }],
            ['mattermost_access', { label: 'MatterMost', value: 'mattermost_access' }],
            ['crowdin', { label:<string>i18n.t('resignmanagement_index_530'), value: 'crowdin' }],
            ['eb_access', { label:<string>i18n.t('constant_index_3331'), value: 'eb_access' }],
            ['ya_access', { label:<string>i18n.t('constant_index_3332'), value: 'ya_access' }],
        ])

        this.statusMap = new Map([
            [0, { label:<string>i18n.t('resignmanagement_index_531'), value: 0 }],
            [1, { label:<string>i18n.t('t240522242'), value: 1 }],
            [2, { label:<string>i18n.t('resignmanagement_index_532'), value: 2 }],
            [3, { label:<string>i18n.t('resignmanagement_index_533'), value: 3 }],
        ])

        this.accomplishedMap = new Map([
            [0, { label:<string>i18n.t('resignmanagement_index_534'), value: 0 }],
            [1, { label:<string>i18n.t('resignmanagement_index_535'), value: 1 }],
        ])

        this.recordStatusMap = new Map([
            [0, { label:<string>i18n.t('resignmanagement_index_531'), value: 0 }],
            [1, { label:<string>i18n.t('t588'), value: 1, operateAlia:<string>i18n.t('execute') }],
            [2, { label:<string>i18n.t('resignmanagement_index_532'), value: 2 }],
            [3, { label:<string>i18n.t('resignmanagement_index_533'), value: 3 }],
        ])
    }

    getByValue(mapType: 'authorizationMap', value): AuthorizationT | undefined
    getByValue(mapType: 'statusMap', value): StatusT | undefined
    getByValue(mapType: 'accomplishedMap', value): AccomplishedT | undefined
    getByValue(mapType: 'recordStatusMap', value): RecordStatusT | undefined
    getByValue(mapType: 'authorizationMap' | 'statusMap' | 'accomplishedMap' | 'recordStatusMap', value) {
        return cloneDeep(this[mapType].get(value as never))
    }

    getOptions(mapType: 'authorizationMap'): AuthorizationT[]
    getOptions(mapType: 'statusMap'): StatusT[]
    getOptions(mapType: 'accomplishedMap'): AccomplishedT[]
    getOptions(mapType: 'authorizationMap' | 'statusMap' | 'accomplishedMap' | 'recordStatusMap') {
        return cloneDeep([...this[mapType].values()])
    }
})()
// 管理端
// 获取离职权限负责人列表
export const getPermissionWhitelistAPI = () =>
    new Promise((resolve, reject) => {
        axios2(`${ajaxUrl.WebAPI}resignation/index-resignation-permission-whitelist`, 'post', {
            decrypt_config: {
                obj: 'permissions.*',
                decrypt_columns: ['nicknames'],
            },
            sys_site: 'CHN',
        })
            .then(res => {
                resolve({
                    data: res.permissions?.map(item => ({
                        id: item.id,
                        type: item.type,
                        typeName: item.permission_name,
                        nickNames: item.nicknames,
                        oldNickNames: cloneDeep(item.nicknames),
                    })),
                })
            })
            .catch(e => {
                console.error('getPermissionWhitelistAPI', e)
                reject(e.error_msg ||<string>i18n.t('serverException'))
            })
            .catch(e => {
                reject(e)
            })
    })

// 编辑离职权限负责人列表
export const editPermissionWhitelistAPI = param =>
    new Promise((resolve, reject) => {
        // 获取 被删除的员工信息
        const exchangeUser: string[] = uniq(difference(param.oldNickNames, param.nickNames))
        const allNickNames = uniq([...param.nickNames, ...param.oldNickNames])
        getUserByNickName(allNickNames)
            .then(userMap => {
                const errorUser = allNickNames.find(nickName => !userMap.getByName(nickName))
                if (errorUser) {
                    return reject(`未查询到【${errorUser}】的相关消息`)
                }
                Promise.all([
                    axios2(`${ajaxUrl.WebAPI}resignation/edit-resignation-permission-whitelist`, 'post', {
                        type: param.type,
                        ids: param.nickNames.map(item => userMap.getByName(item).sfUserId),
                        intact_columns: ['type', 'ids'],
                        sys_site: 'CHN',
                    }),
                ])
                    .then(async res => {
                        // 获取 新 、旧员工的权限信息
                        const rList = await Promise.all(
                            allNickNames.map(nickname =>
                                getStaffAccountAPI(undefined, userMap.getByName(nickname).sfUserId)
                            )
                        )
                        // 获取 旧员工 应该设置的权限
                        const rList2 = await Promise.all(
                            exchangeUser.map(nickname =>
                                getSfUserSfUserOwnerIds(userMap.getByName(nickname).sfUserId)
                            )
                        )
                        // 更新新、旧员工端的权限信息
                        const rList3 = await Promise.all(
                            rList.map(o =>
                                updateResAttrAPI({
                                    ...o,
                                    res_attrs: {
                                        ...o.res_attrs,
                                        sfuser: exchangeUser.includes(o.nickName)
                                            ? [
                                                  {
                                                      owner_id: rList2.find(oo => oo.sfUserId === o.sfUserId)
                                                          .subordinates,
                                                      department_id: 'all',
                                                  },
                                              ]
                                            : [{ owner_id: 'all', department_id: 'all' }],
                                    },
                                })
                            )
                        )
                        resolve(res)
                    })
                    .catch(e => {
                        console.error('editPermissionWhitelistAPI', e)
                        reject(e)
                    })
            })
            .catch(e => {
                console.error('editPermissionWhitelistAPI', e)
                reject(e.error_msg ||<string>i18n.t('serverException'))
            })
    })

// 获取离职员工列表
export const getResignationStaffListAPI = (param, curPage, page) =>
    new Promise((resolve, reject) => {
        getUserByNickName([param.nickName]).then(userMap => {
            const user = userMap.getByName(param.nickName)
            axios2(`${ajaxUrl.WebAPI}resignation/search-resignation-sfusers`, 'post', {
                sfuser_id: param.nickName ? (user ? user.sfUserId : -1) : undefined,
                start_date: param.date ? param.date[0] : undefined,
                end_date: param.date ? param.date[1] : undefined,
                is_accomplished: param.status,
                page: curPage,
                per_page: page,
                intact_columns: ['sfuser_id', 'is_accomplished', 'start_date', 'end_date'],
                decrypt_config: {
                    obj: 'resignation_permission_sfusers.*',
                    decrypt_columns: [
                        'nickname',
                        'sfuser_permission_detail.*.principal_nicknames.*',
                        'sfuser_permission_detail.*.operator_nickname',
                        'sfuser_permission_detail.*.operation_record.*.operator_name',
                    ],
                },
                sys_site: 'CHN',
            })
                .then(res => {
                    resolve({
                        data: res.resignation_permission_sfusers.map(item => ({
                            // 离职日期
                            date: item.resignation_date,
                            nickName: item.nickname,
                            // 完成状态
                            isAccomplished: item.is_accomplished,
                            isAccomplishedLabel: AuthorizationMap.getByValue(
                                'accomplishedMap',
                                item.is_accomplished
                            ).label,
                            detail: item.sfuser_permission_detail.map(i => ({
                                // 权限名（英文）
                                type: i.type,
                                // 权限中文名
                                typeName: i.permission_name,
                                itemStatus: i.status,
                                statusLabel: AuthorizationMap.getByValue('recordStatusMap', i.status)?.label,
                                // 是否延过期
                                postponed: i.ever_postponed,
                                postponedDate: i.postponed_date,
                                // 该权限负责人
                                principalNickNames: i.principal_nicknames?.join('、'),
                                // 操作人
                                operator: i.operator_nickname,
                                // 操作时间
                                operationTime: i.operation_time,
                                remarkShow: i.remark,
                                // eb 自动关闭 操作结果
                                systemRemark: i.system_remark || '',
                                // 操作记录
                                record: i.operation_record.map(a => ({
                                    // 操作记录的id
                                    opId: a.op_id,
                                    // 唯一确定一组（离职员工，离职日期，关闭权限）的id
                                    resignationPermisssionId: a.resignation_permission_sfusers_id,
                                    // 操作(number)
                                    operation: a.operation,
                                    postponedDate: a.postponed_date,
                                    // 操作(string)
                                    operationString: AuthorizationMap.getByValue(
                                        'recordStatusMap',
                                        a.operation
                                    ).label,
                                    // 操作人花名
                                    operator: a.operator_name,
                                    // 备注
                                    remark: a.remark,
                                    // 操作时间(此处取得是更新时间)
                                    operationDate: a.updated_at,
                                })),
                            })),
                        })),
                        total: res.total,
                        currPage: res.current_page,
                    })
                })
                .catch(e => {
                    console.error('ggetResignationStafflistAPI', e)
                    reject(e.error_msg ||<string>i18n.t('serverException'))
                })
        })
    })

// 添加离职员工列表
export const addResignationStaffAPI = (param: number[]) =>
    new Promise((resolve, reject) => {
        getUserBySfUserId(param)
            .then(map => {
                axios2(`${ajaxUrl.WebAPI}resignation/add-resignation-sfusers`, 'post', {
                    sfuser_ids: param,
                    intact_columns: ['sfuser_ids', 'eb_sfusers', 'ya_sfusers', 'apitable_sfusers', 'xapitable_sfusers'],
                    sys_site: 'CHN',
                    eb_sfusers: param.map(o => ({
                        sfuser_id: o,
                        nickname: keyEncrypt(map.getBySfUserId(o).nickName, ebPublicKey),
                    })),
                    ya_sfusers: param.map(o => ({
                        sfuser_id: o,
                        email: keyEncryptYa(map.getBySfUserId(o).email),
                    })),
                    apitable_sfusers: param.map(o => ({
                        sfuser_id: o,
                        email: keyEncrypt(map.getBySfUserId(o).email, apitablePublicKey),
                    })),
                    xapitable_sfusers: param.map(o => ({
                        sfuser_id: o,
                        email: keyEncrypt(map.getBySfUserId(o).email, xapiTablePublicKey),
                    })),
                })
                    .then(res => {
                        resolve({
                            total: res.total,
                        })
                        param.forEach(o => {
                            // 【新部门主管】 发离职通知
                            let commonUserT = map.getBySfUserId(o)
                            sendChangeKnock(
                                commonUserT.direct_supervisor_nickname,
                                '叮咚，' + commonUserT.nickName + ' 离职了，别忘了及时关闭相关应用权限哦！'
                            ).then(() => {})
                            if (commonUserT.direct_supervisor_nickname != commonUserT.supervisor_nickname) {
                                //【新直接主管】
                                sendChangeKnock(
                                    commonUserT.supervisor_nickname,
                                    '叮咚，' +
                                        commonUserT.nickName +
                                        ' 离职了，别忘了及时关闭相关应用权限哦！'
                                ).then(() => {})
                            }
                        })
                    })
                    .catch(e => {
                        console.error('addResignationStaffAPI', e)
                        reject(e.error_msg ||<string>i18n.t('serverException'))
                    })
            })
            .catch(e => reject(e))
    })

