                        email: item.config.to_email,
                        isOn: item.is_on,
                        id: item.id,
                        type: item.type,
                    })),
                })
            })
            .catch(e => {
                console.error('getEmailConfigAPI', e)
                reject(e.error_msg ||<string>i18n.t('serverException'))
            })
    })

