// 获取待处理数据
export const getPendingListAPI = (curPage, perPage) =>
    new Promise((resolve, reject) => {
        axios2(`${ajaxUrl.UserAPI}resignation/to-be-processed-list`, 'post', {
            page: curPage,
            per_page: perPage,
            sys_site: 'CHN',
            decrypt_config: {
                obj: 'to_be_processed_list.*',
                decrypt_columns: ['sfuser_nickname', 'supervisor_nickname', 'email'],
            },
        })
            .then(res => {
                debugger
                resolve({
                    data: res.to_be_processed_list?.map(item => ({
                        id: item.id,
                        postponedDate: item.postponed_date
                            ? dayjs(item.postponed_date).format('YYYY-MM-DD')
                            : '',
                        resignationDate: item.resignation_date,
                        nickName: item.sfuser_nickname,
                        status: item.status,
                        remarkShow: item.remark,
                        statusLabel: AuthorizationMap.getByValue('statusMap', item.status).label,
                        type: item.type,
                        typeLabel: AuthorizationMap.getByValue('authorizationMap', item.type).label,
                        supervisor: item.supervisor_nickname,
                        email: item.email,
                    })),
                    total: res.total,
                    curPage: res.current_page,
                })
            })
            .catch(e => {
                console.error('getPendingListAPI', e)
                reject(e.error_msg ||<string>i18n.t('serverException'))
            })
    })

// 获取历史记录
export const getRecordListAPI = (param, curPage, perPage) =>
    new Promise((resolve, reject) => {
        axios2(`${ajaxUrl.UserAPI}resignation/history`, 'post', {
            nickname: param.nickName,
            type: param.authorization ?? undefined,
            operation: param.handleRecord ?? undefined,
            operator_nickname: param.handleNickName,
            start_date: param.date ? param.date[0] : undefined,
            end_date: param.date ? param.date[1] : undefined,
            page: curPage,
            per_page: perPage,
            sys_site: 'CHN',
            hash_filter: {
                obj: '$this',
                columns: [
                    param.nickName ? 'nickname' : undefined,
                    param.handleNickName ? 'operator_nickname' : undefined,
                ].filter(o => o),
            },
            decrypt_config: {
                obj: 'history_record.*',
                decrypt_columns: ['sfuser_nickname', 'operator_nickname', 'email'],
            },
            intact_columns: ['type', 'operation', 'operator_nickname', 'start_date', 'end_date', 'nickname'],
        })
            .then(res => {
                resolve({
                    data: res.history_record?.map(item => ({
                        id: item.op_id,
                        type: item.type,
                        typeLabel: AuthorizationMap.getByValue('authorizationMap', item.type)?.label,
                        resignationDate: item.resignation_date,
                        operationTime: item.operation_time.split(' ')[0],
                        operation: item.operation,
                        operator: item.operator_nickname,
                        operationLabel:
                            AuthorizationMap.getByValue('recordStatusMap', item.operation)?.operateAlia ||
                            AuthorizationMap.getByValue('recordStatusMap', item.operation)?.label ||
                            '',
                        remark: item.remark,
                        // 后台系统自动操作说明
                        systemRemark: item.system_remark || '',
                        postponedDate: item.postponed_date,
                        nickName: item.sfuser_nickname,
                        email: item.email,
                    })),
                    total: res.total,
                    curPage: res.current_page,
                })
            })
            .catch(e => {
                console.error('getRecordListAPI', e)
                reject(e.error_msg ||<string>i18n.t('serverException'))
            })
    })

